content:
ckend {
            device: Device::Cpu,
            backend: BackendKind::Cpu,
            fallback_used: false,
        }),
        other => Err(format!(
            "Unknown backend: '{other}'. Expected 'cuda', 'openvino', or 'cpu'."
        )),
    }
}
fn resolve_gpu_preferred(
    model_type: ModelType,
    gpu: &GpuCapabilities,
) -> Result<ResolvedBackend, String> {
    // Prefer CUDA
    if gpu.cuda_available {
        return Ok(ResolvedBackend {
            device: Device::Gpu,
            backend: BackendKind::Cuda,
            fallback_used: false,
        });
    }

    // Then OpenVINO (embedding only)
    if gpu.openvino_available && model_type == ModelType::Embedding {
        return Ok(ResolvedBackend {
            device: Device::Gpu,
            backend: BackendKind::OpenVino,
            fallback_used: false,
        });
    }

    // Fallback to CPU
    Ok(ResolvedBackend {
        device: Device::Cpu,
        backend: BackendKind::Cpu,
        fallback_used: true,
    })
}
